using namespace QPI;
struct HM25 { };
struct Random : public ContractBase {
public:
    struct Echo_input{};
    struct Echo_output{};
    struct Burn_input{};
    struct Burn_output{};
    struct GetStats_input {};
    struct GetStats_output {
        uint64 numberOfEchoCalls;
        uint64 numberOfBurnCalls;
    };
private:
    uint64 numberOfEchoCalls;
    uint64 numberOfBurnCalls;
    PUBLIC_PROCEDURE(Echo)
    {
        state.numberOfEchoCalls++;
        if (qpi.invocationReward() > 0) { qpi.transfer(qpi.invocator(), qpi.invocationReward()); }
    }
    PUBLIC_PROCEDURE(Burn)
    {
        state.numberOfBurnCalls++;
        if (qpi.invocationReward() > 0) { qpi.burn(qpi.invocationReward()); }
    }
    PUBLIC_FUNCTION(GetStats)
    {
        output.numberOfBurnCalls = state.numberOfBurnCalls;
        output.numberOfEchoCalls = state.numberOfEchoCalls;
    }
    REGISTER_USER_FUNCTIONS_AND_PROCEDURES
    {
        REGISTER_USER_PROCEDURE(Echo, 1);
        REGISTER_USER_PROCEDURE(Burn, 2);
        REGISTER_USER_FUNCTION(GetStats, 1);
    }
    INITIALIZE
    {
        state.numberOfEchoCalls = 0;
        state.numberOfBurnCalls = 0;
    }
};

// Pattern 1: Refund - procedure doesn't need payment
PUBLIC_PROCEDURE(FreeAction) {
    state.actionCount++;
    if (qpi.invocationReward() > 0) { qpi.transfer(qpi.invocator(), qpi.invocationReward()); }
}
// Pattern 2: Accept payment
PUBLIC_PROCEDURE(PaidAction) {
    if (qpi.invocationReward() >= MINIMUM_PAYMENT) {
        state.totalCollected = state.totalCollected + qpi.invocationReward();
    } else {
        if (qpi.invocationReward() > 0) { qpi.transfer(qpi.invocator(), qpi.invocationReward()); }
    }
}
// Pattern 3: Burn QU to fill execution fee reserve
PUBLIC_PROCEDURE(BurnAction) {
    if (qpi.invocationReward() > 0) { qpi.burn(qpi.invocationReward()); }
}
// qpi.invocator() = caller address, qpi.originator() = original tx signer
// qpi.invocationReward() = QU sent with this call

// Array<T, L> - Fixed array of L elements of type T (L must be power of 2)
Array<uint64, 1024> balances;
// BitArray<L> - Array of L bits (L must be power of 2)
BitArray<256> flags;
// Collection<T, L> - Priority queues per ID point-of-view, capacity L
Collection<OrderData, 65536> orders;
// HashMap<KeyT, ValueT, L> - Hash map, ~constant time lookup/insert/remove
HashMap<id, uint64, 4096> userBalances;
// HashSet<KeyT, L> - Hash set of keys
HashSet<id, 1024> registeredUsers;
// IMPORTANT: Call cleanup() or cleanupIfNeeded() at END_EPOCH if removing items
// L (capacity) must be power of 2 for Array and BitArray

// System procedures are called by the Qubic Core at specific points:
// INITIALIZE - Called once after successful IPO, before construction epoch
INITIALIZE { state.myVar = 0; }
// BEGIN_EPOCH - Called before each epoch starts
BEGIN_EPOCH { /* reset epoch-scoped counters */ }
// END_EPOCH - Called after each epoch ends
END_EPOCH { /* cleanup, distribute rewards */ }
// BEGIN_TICK - Called before each tick's transactions
BEGIN_TICK { /* per-tick setup */ }
// END_TICK - Called after all tick transactions
END_TICK { /* per-tick cleanup */ }
// POST_INCOMING_TRANSFER - Called after QU transferred to this contract
// Input: PostIncomingTransfer_input { id sourceId; sint64 amount; uint8 type; }
// TransferType::procedureTransaction, standardTransaction, qpiTransfer, etc.
// NOTE: qpi.invocator() returns 0 in POST_INCOMING_TRANSFER, use input.sourceId
// All have _WITH_LOCALS variants for local variables

// Local variables on the function call stack are FORBIDDEN in QPI.
// Use _WITH_LOCALS macros and define a _locals struct.

struct MyFunction_locals {
    uint64 tempSum;
    uint32 loopIndex;
};

PUBLIC_FUNCTION_WITH_LOCALS(MyFunction)
{
    locals.tempSum = 0;
    for (locals.loopIndex = 0; locals.loopIndex < 10; locals.loopIndex++)
    {
        locals.tempSum = locals.tempSum + state.values.get(locals.loopIndex);
    }
    output.total = locals.tempSum;
}

// Available macros: PUBLIC_FUNCTION_WITH_LOCALS, PUBLIC_PROCEDURE_WITH_LOCALS,
// PRIVATE_FUNCTION_WITH_LOCALS, PRIVATE_PROCEDURE_WITH_LOCALS,
// INITIALIZE_WITH_LOCALS, BEGIN_EPOCH_WITH_LOCALS, END_EPOCH_WITH_LOCALS, etc.

// PUBLIC_FUNCTION - Read-only, callable by other contracts with larger index
// PRIVATE_FUNCTION - Read-only, NOT callable by other contracts
// PUBLIC_PROCEDURE - State-modifying, callable by other contracts with larger index
// PRIVATE_PROCEDURE - State-modifying, NOT callable by other contracts
// Functions CANNOT modify state. Procedures CAN.
// Functions can be called by procedures, but NOT vice versa.
// Logging is NOT allowed inside functions.
// REGISTER_USER_FUNCTION and REGISTER_USER_PROCEDURE have SEPARATE inputType namespaces.
// The same inputType number CAN be used for both a function and a procedure.

// Issue a new asset with fixed number of shares
// qpi.issueAsset() - creates asset, managed by issuing contract
// Asset name: up to 7 chars, first must be A-Z, rest A-Z or 0-9
// Asset identified by pair (issuer_id, asset_name)
// qpi.transferShareOwnershipAndPossession() - transfer shares
// qpi.releaseShares() / qpi.acquireShares() - transfer management rights
// QX contract is the standard exchange for trading assets
// 676 contract shares created after IPO, shareholders receive passive income
// qpi.numberOfShares() - query share count with optional filters

// Reading contract state via RPC:
const HM25_CONTRACT_INDEX = 12;
const FUNC_GET_STATS = 1;
const queryData = { contractIndex: HM25_CONTRACT_INDEX, inputType: FUNC_GET_STATS, inputSize: 0, requestData: '' };
const response = await fetch(`${endpoint}/v1/querySmartContract`, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(queryData) });
const json = await response.json();
const raw = base64.decode(json.responseData);
const buf = Buffer.from(raw, 'binary');
// Parse per output struct (uint64 = 8 bytes LE)
const echoCalls = buf.readBigUInt64LE(0);
const burnCalls = buf.readBigUInt64LE(8);

// Executing procedures requires building + signing a transaction
// Transaction targets contract by setting destination to contract index
// inputType identifies which procedure (e.g. PROC_ECHO=1, PROC_BURN=2)
// Then broadcast via POST /v1/broadcast-transaction

// Pattern: Contract that consumes Oracle Machine price data
using namespace QPI;

struct PRICETRACKER : public ContractBase {
public:
    // State
    sint64 lastPriceNumerator;
    sint64 lastPriceDenominator;
    uint32 lastUpdateTick;
    uint64 totalQueries;

    // Oracle callback receives price data after Quorum verification
    struct UpdatePrice_input {
        sint64 numerator;
        sint64 denominator;
        uint32 sourceTick;
    };
    struct UpdatePrice_output {};

    struct GetPrice_input {};
    struct GetPrice_output {
        sint64 numerator;
        sint64 denominator;
        uint32 lastUpdateTick;
    };

    PUBLIC_PROCEDURE(UpdatePrice)
    {
        // Refund invocation reward if sent
        if (qpi.invocationReward() > 0) {
            qpi.transfer(qpi.invocator(), qpi.invocationReward());
        }
        state.lastPriceNumerator = input.numerator;
        state.lastPriceDenominator = input.denominator;
        state.lastUpdateTick = input.sourceTick;
        state.totalQueries = state.totalQueries + 1;
    }

    PUBLIC_FUNCTION(GetPrice)
    {
        output.numerator = state.lastPriceNumerator;
        output.denominator = state.lastPriceDenominator;
        output.lastUpdateTick = state.lastUpdateTick;
    }

    REGISTER_USER_FUNCTIONS_AND_PROCEDURES
        REGISTER_USER_PROCEDURE(UpdatePrice, 1);
        REGISTER_USER_FUNCTION(GetPrice, 1);
    END_REGISTER_USER_FUNCTIONS_AND_PROCEDURES

    INITIALIZE {
        state.lastPriceNumerator = 0;
        state.lastPriceDenominator = 1;
        state.lastUpdateTick = 0;
        state.totalQueries = 0;
    }
};

VULNERABILITY: uint64 silently wraps on overflow (max 18,446,744,073,709,551,615).

Example (VULNERABLE):
PUBLIC_PROCEDURE(Deposit) {
    state.balance = state.balance + input.amount;  // OVERFLOW if balance near MAX
}

Fix -- add bounds check:
PUBLIC_PROCEDURE(Deposit) {
    if (state.balance + input.amount >= state.balance) {  // overflow check
        state.balance = state.balance + input.amount;
    }
}

Or use saturating arithmetic pattern:
// Saturating add: result = min(a + b, MAX_UINT64)
if (input.amount > 0 && state.balance > 18446744073709551615ULL - input.amount) {
    // Would overflow -- reject or cap
} else {
    state.balance = state.balance + input.amount;
}

Also applies to: sint64 (signed overflow is undefined behavior), uint32, multiplication overflow.

VULNERABILITY: If a PUBLIC_PROCEDURE does not handle invocationReward(), QU sent by callers is permanently locked.

Every transaction invoking a procedure can include an amount (invocation reward). If the procedure does not explicitly transfer or burn it, the QU stays in the contract balance with no way to recover.

Example (VULNERABLE):
PUBLIC_PROCEDURE(DoSomething) {
    state.counter = state.counter + 1;
    // invocationReward() not handled -- QU locked forever!
}

Fix -- refund pattern:
PUBLIC_PROCEDURE(DoSomething) {
    if (qpi.invocationReward() > 0) {
        qpi.transfer(qpi.invocator(), qpi.invocationReward());
    }
    state.counter = state.counter + 1;
}

Or if procedure requires payment:
PUBLIC_PROCEDURE(PaidAction) {
    if (qpi.invocationReward() < REQUIRED_FEE) {
        // Refund and abort
        if (qpi.invocationReward() > 0) {
            qpi.transfer(qpi.invocator(), qpi.invocationReward());
        }
        return;
    }
    // Keep fee, refund excess
    sint64 excess = qpi.invocationReward() - REQUIRED_FEE;
    if (excess > 0) {
        qpi.transfer(qpi.invocator(), excess);
    }
    qpi.burn(REQUIRED_FEE);
    // ... do work
}

VULNERABILITY: In PUBLIC_FUNCTION, the state parameter is const. Any assignment to state.xxx compiles but silently does nothing -- the change is discarded.

Example (VULNERABLE -- compiles but state never changes):
PUBLIC_FUNCTION(IncrementCounter) {
    state.counter = state.counter + 1;  // SILENT BUG: state is const!
    output.newValue = state.counter;     // Returns old value
}

Fix -- use PUBLIC_PROCEDURE for state changes:
PUBLIC_PROCEDURE(IncrementCounter) {
    if (qpi.invocationReward() > 0) {
        qpi.transfer(qpi.invocator(), qpi.invocationReward());
    }
    state.counter = state.counter + 1;  // Works -- state is mutable in procedures
}

Rule: PUBLIC_FUNCTION = read-only query. PUBLIC_PROCEDURE = state mutation.
Also: qpi.transfer(), qpi.burn(), qpi.issueAsset() are forbidden in PUBLIC_FUNCTION.

VULNERABILITY: State accessed in END_EPOCH and BEGIN_EPOCH runs at epoch boundaries. User procedures run during ticks. If state is shared, race conditions can occur.

System procedure execution order at epoch boundary:
1. Last tick of epoch N finishes
2. END_EPOCH runs (cleanup, snapshot)
3. Revenue donations processed (POST_INCOMING_TRANSFER with TransferType::revenueDonation)
4. IPO refunds processed
5. BEGIN_EPOCH runs (reset counters, initialize new epoch)
6. First tick of epoch N+1 starts

Example (VULNERABLE):
END_EPOCH {
    state.epochRewards = state.totalFees;  // snapshot
    state.totalFees = 0;                    // reset
}
PUBLIC_PROCEDURE(PayFee) {
    state.totalFees = state.totalFees + qpi.invocationReward();
    // If this runs in last tick and END_EPOCH runs immediately after,
    // the fee from this tick may or may not be included in epochRewards
}

Fix: Use separate accumulators and swap at epoch boundary.
END_EPOCH {
    state.epochRewards = state.currentEpochFees;
    state.currentEpochFees = 0;
}

HashMap, HashSet, and Collection do not reclaim slots when items are removed. This degrades lookup performance over time.

Pattern: Call cleanup() or reset() at END_EPOCH.

struct MYCONTRACT : public ContractBase {
    HashMap<id, uint64, 1024> balances;  // capacity must be power of 2
    HashSet<id, 256> blacklist;

    END_EPOCH {
        // Option 1: cleanup() -- reclaims removed slots, keeps existing data
        state.balances.cleanup();
        state.blacklist.cleanup();

        // Option 2: reset() -- clears everything (use if data is per-epoch)
        // state.balances.reset();
    }

    // Alternative: call cleanupIfNeeded() after procedures that do many removes
    PUBLIC_PROCEDURE(RemoveUser) {
        state.balances.remove(input.userId);
        state.balances.cleanupIfNeeded();  // only runs if fragmentation is high
    }
};

Performance: cleanup() is expensive (rehashes all entries). Only call at epoch boundaries or after bulk removes.
Capacity: HashMap/HashSet performance degrades above 80% population. Size capacity accordingly.

Contracts can call user functions and procedures of other contracts.

Calling a function (read-only, returns data):
// From within a procedure or function:
OtherContract::GetPrice_input fnInput;
OtherContract::GetPrice_output fnOutput;
qpi.callFunction(OTHER_CONTRACT_INDEX, fnInput, fnOutput);
// fnOutput now contains the result

Invoking a procedure (state-changing, requires QU transfer):
// From within a procedure:
OtherContract::Deposit_input procInput;
procInput.amount = 1000;
qpi.invokeProcedure(OTHER_CONTRACT_INDEX, procInput, TRANSFER_AMOUNT);
// TRANSFER_AMOUNT QU sent as invocation reward

Rules:
- Functions can call other functions (read-only chain)
- Procedures can call functions and invoke procedures
- Functions CANNOT invoke procedures (state-changing)
- Cross-contract calls add to the recursion depth (limit: 10)
- The invoked procedure's POST_INCOMING_TRANSFER fires with TransferType::qpiTransfer

Caution: If the target contract procedure calls back, beware of reentrancy patterns.

The RANDOM contract (contract index 2) provides verifiable randomness on Qubic.

Pattern for consuming randomness in your contract:
struct LOTTERY : public ContractBase {
    Array<id, 256> participants;
    uint32 participantCount;
    uint64 prizePool;

    PUBLIC_PROCEDURE(Enter) {
        if (qpi.invocationReward() < ENTRY_FEE) {
            if (qpi.invocationReward() > 0)
                qpi.transfer(qpi.invocator(), qpi.invocationReward());
            return;
        }
        sint64 excess = qpi.invocationReward() - ENTRY_FEE;
        if (excess > 0)
            qpi.transfer(qpi.invocator(), excess);

        state.participants.set(state.participantCount, qpi.invocator());
        state.participantCount = state.participantCount + 1;
        state.prizePool = state.prizePool + ENTRY_FEE;
    }

    // Draw winner using tick-based entropy
    PUBLIC_PROCEDURE(Draw) {
        if (qpi.invocationReward() > 0)
            qpi.transfer(qpi.invocator(), qpi.invocationReward());
        if (state.participantCount == 0) return;
        // Use tick number as entropy source (simple approach)
        uint32 winnerIdx = mod(qpi.tick(), state.participantCount);
        id winner = state.participants.get(winnerIdx);
        qpi.transfer(winner, state.prizePool);
        state.prizePool = 0;
        state.participantCount = 0;
    }
};

Note: For production randomness, use the RANDOM contract's output or Computor-derived entropy rather than tick number alone.

Pattern for a token contract using QPI asset management:

using namespace QPI;
struct MYTOKEN : public ContractBase {
    uint64 totalSupply;
    uint64 maxSupply;

    struct Mint_input { uint64 amount; };
    struct Mint_output {};
    struct GetSupply_input {};
    struct GetSupply_output { uint64 total; uint64 max; };

    INITIALIZE {
        // Issue asset during initialization (after IPO)
        // Asset name: 1-7 chars, first A-Z, rest A-Z/0-9
        qpi.issueAsset(MYTKN, SELF, 0, 1000000, 1);  // name, issuer, managingRight, numShares, unitOfMeasurement
        state.totalSupply = 1000000;
        state.maxSupply = 10000000;
    }

    PUBLIC_PROCEDURE(Mint) {
        if (qpi.invocationReward() > 0)
            qpi.transfer(qpi.invocator(), qpi.invocationReward());
        if (state.totalSupply + input.amount > state.maxSupply) return;
        if (state.totalSupply + input.amount < state.totalSupply) return;  // overflow check
        qpi.issueAsset(MYTKN, SELF, 0, input.amount, 1);
        state.totalSupply = state.totalSupply + input.amount;
    }

    PUBLIC_FUNCTION(GetSupply) {
        output.total = state.totalSupply;
        output.max = state.maxSupply;
    }

    REGISTER_USER_FUNCTIONS_AND_PROCEDURES
        REGISTER_USER_PROCEDURE(Mint, 1);
        REGISTER_USER_FUNCTION(GetSupply, 1);
    END_REGISTER_USER_FUNCTIONS_AND_PROCEDURES
};

Asset Name Rules: 1-7 characters. First character A-Z. Remaining A-Z or 0-9.
Shares can be transferred via qpi.transferShareOwnershipAndPossession().

AMM pattern using constant-product formula (x*y=k) in QPI:
struct AMM_locals { uint64 amountOut; uint64 newReserveA; uint64 newReserveB; };
PUBLIC_PROCEDURE_WITH_LOCALS(Swap) {
    if (qpi.invocationReward() == 0) return;
    // x * y = k invariant
    locals.amountOut = div(state.reserveB * qpi.invocationReward(), state.reserveA + qpi.invocationReward());
    if (locals.amountOut == 0) { qpi.transfer(qpi.invocator(), qpi.invocationReward()); return; }
    state.reserveA = state.reserveA + qpi.invocationReward();
    state.reserveB = state.reserveB - locals.amountOut;
    qpi.transfer(qpi.invocator(), locals.amountOut);
}
Note: Use div() not / operator. Validate reserves > 0 before swap. No floating point.

Distribute QU to all shareholders at epoch end:
END_EPOCH {
    if (state.epochRevenue == 0) return;
    // qpi.distributeDividends(amount) distributes proportionally to all 676 shareholders
    // Amount is total QU to distribute -- split by share ownership automatically
    qpi.distributeDividends(state.epochRevenue);
    state.epochRevenue = 0;
}
// Accumulate revenue during epoch:
PUBLIC_PROCEDURE(AcceptPayment) {
    state.epochRevenue = state.epochRevenue + qpi.invocationReward();
}
// Rules:
// - Only callable in system procedures (BEGIN/END_EPOCH, POST_INCOMING_TRANSFER)
// - NOT callable inside PUBLIC_PROCEDURE or PUBLIC_FUNCTION
// - Distributes to 676 IPO shareholders proportionally
// - Triggers POST_INCOMING_TRANSFER on receiving contracts with TransferType::qpiDistributeDividends

Contracts can participate in IPOs of other contracts using qpi.bidInIPO():
// Bid on another contract IPO from within a procedure:
PUBLIC_PROCEDURE(BidOnIPO) {
    if (qpi.invocationReward() < BID_AMOUNT) {
        if (qpi.invocationReward() > 0) qpi.transfer(qpi.invocator(), qpi.invocationReward());
        return;
    }
    // Bid on contract at index TARGET_INDEX, price = pricePerShare, quantity = numShares
    qpi.bidInIPO(TARGET_CONTRACT_INDEX, input.pricePerShare, input.numShares);
    sint64 excess = qpi.invocationReward() - (input.pricePerShare * input.numShares);
    if (excess > 0) qpi.transfer(qpi.invocator(), excess);
}
// If IPO bid is not filled:
// - Refund arrives via POST_INCOMING_TRANSFER with TransferType::ipoBidRefund
// - Use input.sourceId (NOT qpi.invocator()) for the source
// Cannot call qpi.bidInIPO() from POST_INCOMING_TRANSFER callback.

