// Inner-contract calls use CALL(functionOrProcedure, input, output)

struct square_input
{
    sint64 a;
};
struct square_output
{
    sint64 out;
};

PRIVATE_FUNCTION(square)
{
    output.out = input.a * input.a;
}

struct sumSquareOneToTen_input
{
};
struct sumSquareOneToTen_output
{
    sint64 sum;
};
struct sumSquareOneToTen_locals
{
    sint64 i;
    square_input squareInput;
    square_output squareOutput;
};

PUBLIC_FUNCTION_WITH_LOCALS(sumSquareOneToTen)
{
    for (locals.i = 1; locals.i <= 10; ++locals.i)
    {
        output.sum += locals.i;
    }
    locals.squareInput.a = output.sum;
    CALL(square, locals.squareInput, locals.squareOutput);
    output.sum = locals.squareOutput.out;
}

// Key rules:
// - Define input/output for inner call in _locals struct
// - Use PRIVATE_FUNCTION/PRIVATE_PROCEDURE for internal-only helpers
// - CALL() macro for same-contract calls
// - CALL_OTHER_CONTRACT_FUNCTION() for cross-contract

// State is persistent data -- member variables in the contract struct.
// It must remain identical across all nodes for consensus.
// The state is passed as a reference named 'state'.

struct MYTEST : public ContractBase
{
public:
    sint64 myNumber;

    struct changeNumber_input
    {
        sint64 myNumber;
    };
    struct changeNumber_output
    {
    };

    // CORRECT: procedure can modify state
    PUBLIC_PROCEDURE(changeNumber)
    {
        state.myNumber = input.myNumber;
    }

    // WRONG: function CANNOT modify state
    // PUBLIC_FUNCTION(changeNumber)
    // {
    //     state.myNumber = input.myNumber; // ERROR: expression must be a modifiable lvalue
    // }

    struct getNumber_input {};
    struct getNumber_output { sint64 myNumber; };

    PUBLIC_FUNCTION(getNumber)
    {
        output.myNumber = state.myNumber;
    }

    REGISTER_USER_FUNCTIONS_AND_PROCEDURES()
    {
        REGISTER_USER_PROCEDURE(changeNumber, 1);
        REGISTER_USER_FUNCTION(getNumber, 1);
    }

    INITIALIZE()
    {
        state.myNumber = 0;
    }
};

